/// Look up a move's sprite by lowercase move id (e.g. "surf"). O(log N).
pub fn move_sprite(move_id: &str) -> Option<&'static [u8]> {
    MOVE_SPRITES
        .binary_search_by(|(id, _)| (*id).cmp(move_id))
        .ok()
        .map(|i| &MOVE_SPRITES[i].1[..])
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Every gen1_battle move id (the keys of rby_moves.json), all 165.
    const GEN1_MOVE_IDS: [&str; 165] = [
        "absorb", "acid", "acidarmor", "agility", "amnesia", "aurorabeam", "barrage",
        "barrier", "bide", "bind", "bite", "blizzard", "bodyslam", "boneclub", "bonemerang",
        "bubble", "bubblebeam", "clamp", "cometpunch", "confuseray", "confusion", "constrict",
        "conversion", "counter", "crabhammer", "cut", "defensecurl", "dig", "disable",
        "dizzypunch", "doubleedge", "doublekick", "doubleslap", "doubleteam", "dragonrage",
        "dreameater", "drillpeck", "earthquake", "eggbomb", "ember", "explosion", "fireblast",
        "firepunch", "firespin", "fissure", "flamethrower", "flash", "fly", "focusenergy",
        "furyattack", "furyswipes", "glare", "growl", "growth", "guillotine", "gust", "harden",
        "haze", "headbutt", "highjumpkick", "hornattack", "horndrill", "hydropump",
        "hyperbeam", "hyperfang", "hypnosis", "icebeam", "icepunch", "jumpkick", "karatechop",
        "kinesis", "leechlife", "leechseed", "leer", "lick", "lightscreen", "lovelykiss",
        "lowkick", "meditate", "megadrain", "megakick", "megapunch", "metronome", "mimic",
        "minimize", "mirrormove", "mist", "nightshade", "payday", "peck", "petaldance",
        "pinmissile", "poisongas", "poisonpowder", "poisonsting", "pound", "psybeam",
        "psychic", "psywave", "quickattack", "rage", "razorleaf", "razorwind", "recover",
        "reflect", "rest", "roar", "rockslide", "rockthrow", "rollingkick", "sandattack",
        "scratch", "screech", "seismictoss", "selfdestruct", "sharpen", "sing", "skullbash",
        "skyattack", "slam", "slash", "sleeppowder", "sludge", "smog", "smokescreen",
        "softboiled", "solarbeam", "sonicboom", "spikecannon", "splash", "spore", "stomp",
        "strength", "stringshot", "struggle", "stunspore", "submission", "substitute",
        "superfang", "supersonic", "surf", "swift", "swordsdance", "tackle", "tailwhip",
        "takedown", "teleport", "thrash", "thunder", "thunderbolt", "thunderpunch",
        "thundershock", "thunderwave", "toxic", "transform", "triattack", "twineedle",
        "vinewhip", "visegrip", "waterfall", "watergun", "whirlwind", "wingattack", "withdraw",
        "wrap",
    ];

    #[test]
    fn every_gen1_move_resolves() {
        assert_eq!(MOVE_SPRITES.len(), GEN1_MOVE_IDS.len());
        for id in GEN1_MOVE_IDS {
            let sprite =
                move_sprite(id).unwrap_or_else(|| panic!("no sprite for move id {id}"));
            assert_eq!(sprite.len(), MOVE_SPRITE_BYTES);
        }
        assert!(move_sprite("notamove").is_none());
        assert!(move_sprite("").is_none());
    }
}
